// Phase B1..B5: D-1 заезд, D-0 morning, D-0 evening, D-1 выезд, D+1 review могут идти гостю; иначе владельцу.
function dayDiff(dateStrYmd, today){
  const d = new Date(dateStrYmd + 'T00:00:00Z');
  const t = new Date(today.toISOString().slice(0,10) + 'T00:00:00Z');
  return Math.round((d - t) / 86400000);
}
const today = new Date();
const out = [];
for (const it of $input.all()) {
  const b = it.json;
  if (!b || !b.id) continue;
  const ci = String(b.checkin_at  || '').slice(0,10);
  const co = String(b.checkout_at || '').slice(0,10);
  if (ci.length < 10 || co.length < 10) continue;
  const dCi = dayDiff(ci, today);
  const dCo = dayDiff(co, today);
  let sent = b.journey_sent;
  if (typeof sent === 'string') { try { sent = JSON.parse(sent); } catch(e){ sent={}; } }
  if (!sent || typeof sent !== 'object') sent = {};
  const hasGuest = b.guest_chat_id !== null && b.guest_chat_id !== undefined && b.guest_chat_id !== '';
  const evs = [];
  // === D-1 заезд (B1) ===
  if (dCi === 1) {
    if (hasGuest && !sent['guest_d_minus_1_checkin']) {
      evs.push({ event_key: 'guest_d_minus_1_checkin', channel: 'guest', chat_id: Number(b.guest_chat_id) });
    } else if (!hasGuest && !sent['owner_d_minus_1_checkin']) {
      evs.push({ event_key: 'owner_d_minus_1_checkin', channel: 'owner', chat_id: null });
    }
  }
  // === D-0 morning (B2) ===
  if (dCi === 0) {
    if (hasGuest && !sent['guest_d_0_morning_checkin']) {
      evs.push({ event_key: 'guest_d_0_morning_checkin', channel: 'guest', chat_id: Number(b.guest_chat_id) });
    } else if (!hasGuest && !sent['owner_d_0_morning_checkin']) {
      evs.push({ event_key: 'owner_d_0_morning_checkin', channel: 'owner', chat_id: null });
    }
    // === D-0 evening (B3) ===
    if (hasGuest && !sent['guest_d_0_evening_checkin']) {
      evs.push({ event_key: 'guest_d_0_evening_checkin', channel: 'guest', chat_id: Number(b.guest_chat_id) });
    } else if (!hasGuest && !sent['owner_d_0_evening_checkin']) {
      evs.push({ event_key: 'owner_d_0_evening_checkin', channel: 'owner', chat_id: null });
    }
  }
  // === D-1 выезд (B4) ===
  if (dCo === 1) {
    if (hasGuest && !sent['guest_d_minus_1_checkout']) {
      evs.push({ event_key: 'guest_d_minus_1_checkout', channel: 'guest', chat_id: Number(b.guest_chat_id) });
    } else if (!hasGuest && !sent['owner_d_minus_1_checkout']) {
      evs.push({ event_key: 'owner_d_minus_1_checkout', channel: 'owner', chat_id: null });
    }
  }
  // === D+1 review (Phase B5) — guest first, иначе owner ===
  if (dCo === -1) {
    if (hasGuest && !sent['guest_d_plus_1_review']) {
      evs.push({ event_key: 'guest_d_plus_1_review', channel: 'guest', chat_id: Number(b.guest_chat_id) });
    } else if (!hasGuest && !sent['owner_d_plus_1_review']) {
      evs.push({ event_key: 'owner_d_plus_1_review', channel: 'owner', chat_id: null });
    }
  }
  for (const e of evs) {
    out.push({ json: {
      booking_id: String(b.id),
      event_key: e.event_key,
      channel: e.channel,
      chat_id: e.chat_id,
      apartment_id:   String(b.apartment_id),
      apartment_name: String(b.apartment_name || ''),
      checkin_at:     ci,
      checkout_at:    co,
      source:         String(b.source || ''),
      guest_name:     String(b.guest_name || ''),
      guest_first_name: String(b.guest_first_name || ''),
      guest_username:   String(b.guest_username || ''),
      d_ci: dCi, d_co: dCo
    } });
  }
}
return out;

const j = $json;
const HOMERESERVE_URL = 'https://homereserve.ru/m66FXMW0XO/list-preview';

const apt         = '№' + j.apartment_id + (j.apartment_name ? ' (' + j.apartment_name + ')' : '');
const dates       = j.checkin_at + ' → ' + j.checkout_at;
const src         = j.source || 'не указан';
const guest       = (j.guest_name && j.guest_name.trim()) ? j.guest_name : 'гость не указан';
const guestFirst  = (j.guest_first_name && j.guest_first_name.trim()) ? j.guest_first_name : '';
const guestUsername = j.guest_username ? '@' + j.guest_username : '';

// render() — substitutes {{placeholder}} with context values
function render(body, ctx) {
  return body
    .replace(/\{\{guest_first_name\}\}/g,  ctx.guest_first_name)
    .replace(/\{\{apartment_id\}\}/g,       ctx.apartment_id)
    .replace(/\{\{apartment_name\}\}/g,     ctx.apartment_name)
    .replace(/\{\{checkin_at\}\}/g,         ctx.checkin_at)
    .replace(/\{\{checkout_at\}\}/g,        ctx.checkout_at)
    .replace(/\{\{guest_name\}\}/g,         ctx.guest_name)
    .replace(/\{\{guest_username\}\}/g,     ctx.guest_username)
    .replace(/\{\{booking_id\}\}/g,         ctx.booking_id)
    .replace(/\{\{source\}\}/g,             ctx.source)
    .replace(/\{\{homereserve_url\}\}/g,    ctx.homereserve_url)
    .replace(/\{\{guest_chat_id\}\}/g,      ctx.guest_chat_id)
    .trim();
}

const ctx = {
  guest_first_name: guestFirst ? ', ' + guestFirst : '',
  apartment_id:     String(j.apartment_id),
  apartment_name:   j.apartment_name ? ' (' + j.apartment_name + ')' : '',
  checkin_at:       j.checkin_at,
  checkout_at:      j.checkout_at,
  guest_name:       guest,
  guest_username:   guestUsername,
  booking_id:       j.booking_id || j.id || '',
  source:           src,
  homereserve_url:  HOMERESERVE_URL,
  guest_chat_id:    j.guest_chat_id ? String(j.guest_chat_id) : '',
};

// load templates map from Load Templates node (parallel branch)
let tplMap = {};
try {
  const tplItems = $('Load Templates').all();
  for (const item of tplItems) {
    const t = item.json;
    if (t && t.key && t.body) tplMap[t.key] = t.body;
  }
} catch (_e) {
  // Load Templates node did not run or errored — fallback to hardcoded
}

function fromDB(key) {
  if (tplMap[key]) return { text: render(tplMap[key], ctx), source: 'message_templates' };
  return null;
}

// ── Hardcoded fallback ─────────────────────────────────────────────────────
const M = {
  guest_d_minus_1_checkin:
    'Здравствуйте' + (guestFirst ? ', ' + guestFirst : '') + '!\n' +
    'Завтра ваш заезд в Акваторинг.\n\n' +
    'Бронь:\nобъект ' + apt + '\nдаты: ' + dates + '\n\n' +
    'Заезд обычно с 14:00. Если время приезда меняется — напишите здесь, я передам владельцу.\n\n' +
    'Ссылка для просмотра объекта и деталей:\n' + HOMERESERVE_URL + '\n\nДо встречи!',
  guest_d_0_morning_checkin:
    'Доброе утро' + (guestFirst ? ', ' + guestFirst : '') + '!\n' +
    'Сегодня ваш заезд в Акваторинг.\n\n' +
    'Бронь:\nобъект ' + apt + '\nдаты: ' + dates + '\n\n' +
    'Заезд обычно с 14:00.\n\n' +
    'Если время приезда меняется или нужен уточняющий вопрос по заселению — напишите здесь.\n\n' +
    'Ссылка для просмотра объекта:\n' + HOMERESERVE_URL + '\n\nДо встречи!',
  guest_d_0_evening_checkin:
    'Добрый вечер' + (guestFirst ? ', ' + guestFirst : '') + '! Надеюсь, вы хорошо заселились.\n\n' +
    'Всё ли в порядке с номером?\n' +
    'Если что-то нужно — напишите здесь, я передам владельцу.\n\n' +
    'Желаем приятного отдыха в Акваторинге!',
  guest_d_minus_1_checkout:
    'Здравствуйте' + (guestFirst ? ', ' + guestFirst : '') + '!\n' +
    'Напоминаю, что завтра день выезда из Акваторинга.\n\n' +
    'Бронь:\nобъект ' + apt + '\nдаты: ' + dates + '\n\n' +
    'Выезд обычно до 12:00.\n\n' +
    'Если нужен поздний выезд или есть вопрос по завершению проживания — напишите здесь, я передам владельцу.\n\n' +
    'Спасибо, что выбрали Акваторинг!',
  guest_d_plus_1_review:
    'Здравствуйте' + (guestFirst ? ', ' + guestFirst : '') + '! Спасибо, что выбрали Акваторинг.\n\n' +
    'Надеемся, отдых прошёл хорошо.\n\n' +
    'Если всё понравилось, будем благодарны за короткий отзыв — это очень помогает нам развивать гостевой дом.\n\n' +
    'Если что-то было не так или остался вопрос — напишите здесь, я передам владельцу.\n\n' +
    'Будем рады видеть вас снова!',
  owner_d_minus_1_checkin:  'Завтра заезд: объект ' + apt + '. Даты: ' + dates + '. Источник: ' + src + '. Гость: ' + guest + '. Подготовить уборку, ключи, инструкции.',
  owner_d_0_morning_checkin:'Сегодня заезд: объект ' + apt + '. Гость: ' + guest + '. Проверь готовность номера, ключи, связь с гостем и инструкцию по заселению.',
  owner_d_0_evening_checkin:'Сегодня было заселение: объект ' + apt + '. Гость: ' + guest + '. Проверь, всё ли у гостей хорошо.',
  owner_d_minus_1_checkout: 'Завтра выезд: объект ' + apt + ' до 12:00. Гость: ' + guest + '. Подготовить уборку и проверку номера.',
  owner_d_plus_1_review:    'Вчера был выезд: объект ' + apt + '. Гость: ' + guest + '. Если есть контакт гостя — попросить отзыв и закрыть бытовые вопросы.'
};

const ownerBriefMap = {
  guest_d_minus_1_checkin:
    'Гостю отправлено D-1 сообщение по брони ' + j.booking_id + ':\n' +
    'объект ' + apt + '\nдаты ' + dates + '\n' +
    'Telegram: ' + (guestUsername || ('id ' + (j.chat_id || '—'))) + '\nguest_chat_id: есть',
  guest_d_0_morning_checkin:
    'Гостю отправлено сообщение в день заезда по брони ' + j.booking_id + ':\n' +
    'объект ' + apt + '\nдаты ' + dates + '\n' +
    'Telegram: ' + (guestUsername || ('id ' + (j.chat_id || '—'))) + '\nguest_chat_id: есть',
  guest_d_0_evening_checkin:
    'Гостю отправлен вечерний check-in по брони ' + j.booking_id + ':\n' +
    'объект ' + apt + '\nдаты ' + dates + '\n' +
    'Telegram: ' + (guestUsername || ('id ' + (j.chat_id || '—'))) + '\nguest_chat_id: есть',
  guest_d_minus_1_checkout:
    'Гостю отправлено напоминание о завтрашнем выезде по брони ' + j.booking_id + ':\n' +
    'объект ' + apt + '\nдаты ' + dates + '\n' +
    'Telegram: ' + (guestUsername || ('id ' + (j.chat_id || '—'))) + '\nguest_chat_id: есть',
  guest_d_plus_1_review:
    'Гостю отправлена просьба об отзыве по брони ' + j.booking_id + ':\n' +
    'объект ' + apt + '\nдаты ' + dates + '\n' +
    'Telegram: ' + (guestUsername || ('id ' + (j.chat_id || '—'))) + '\nguest_chat_id: есть'
};

// ── Resolve main message ───────────────────────────────────────────────────
let messageText, templateSource;
const msgFromDB = fromDB(j.event_key);
if (msgFromDB) {
  messageText    = msgFromDB.text;
  templateSource = msgFromDB.source;
} else {
  messageText    = M[j.event_key] || ('Touchpoint ' + j.event_key + ': ' + apt);
  templateSource = 'fallback_hardcoded';
}

// ── Resolve owner brief ────────────────────────────────────────────────────
let ownerBriefText = '', ownerBriefSource = '';
if (j.channel === 'guest') {
  const briefKey = 'owner_brief_' + j.event_key + '_sent';
  const briefFromDB = fromDB(briefKey);
  if (briefFromDB) {
    ownerBriefText  = briefFromDB.text;
    ownerBriefSource = briefFromDB.source;
  } else {
    ownerBriefText   = ownerBriefMap[j.event_key] || '';
    ownerBriefSource = 'fallback_hardcoded';
  }
}

return { ...j, message_text: messageText, owner_brief_text: ownerBriefText, template_source: templateSource, owner_brief_source: ownerBriefSource };
